func (s *Server) handleSetRank(cmd Command) {
	if cmd.Sender.Role != RoleAdmin {
		s.sendToUser(cmd.Sender, Message{
			Type:    "error",
			Content: "You don't have permission to use this command",
		})
		return
	}

	if len(cmd.Args) < 2 {
		s.sendToUser(cmd.Sender, Message{
			Type:    "error",
			Content: "Usage: /setrank <username> <admin|moderator|user>",
		})
		return
	}

	targetUsername := cmd.Args[0]
	newRole := Role(cmd.Args[1])

	if newRole != RoleAdmin && newRole != RoleModerator && newRole != RoleUser {
		s.sendToUser(cmd.Sender, Message{
			Type:    "error",
			Content: "Invalid role. Use: admin, moderator, or user",
		})
		return
	}

	s.mu.Lock()
	var target *User
	for _, u := range s.users {
		if u.Username == targetUsername {
			target = u
			break
		}
	}

	if target != nil {
		target.Role = newRole
	}
	s.mu.Unlock()

	if target == nil {
		s.sendToUser(cmd.Sender, Message{
			Type:    "error",
			Content: fmt.Sprintf("User not found: %s", targetUsername),
		})
		return
	}

	s.sendToUser(target, Message{
		Type:    "rank_changed",
		Content: fmt.Sprintf("Your rank has been changed to: %s", newRole),
	})

	s.sendToUser(cmd.Sender, Message{
		Type:    "success",
		Content: fmt.Sprintf("Changed %s's rank to %s", targetUsername, newRole),
	})

	log.Printf("%s changed %s's rank to %s", cmd.Sender.Username, targetUsername, newRole)
}

func (s *Server) handleListUsers(cmd Command) {
	s.mu.RLock()
	userList := make([]map[string]string, 0, len(s.users))
	for _, u := range s.users {
		userList = append(userList, map[string]string{
			"username": u.Username,
			"id":       u.ID,
			"role":     string(u.Role),
		})
	}
	s.mu.RUnlock()

	s.sendToUser(cmd.Sender, Message{
		Type:    "user_list",
		Content: fmt.Sprintf("Total users online: %d", len(userList)),
		Data:    userList,
	})
}

func (s *Server) broadcastMessage(msg Message) {
	data, err := json.Marshal(msg)
	if err != nil {
		log.Printf("Error marshaling message: %v", err)
		return
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	for _, user := range s.users {
		user.mu.Lock()
		err := user.Conn.WriteMessage(websocket.TextMessage, data)
		user.mu.Unlock()
		if err != nil {
			log.Printf("Error sending to user %s: %v", user.Username, err)
		}
	}
}

func (s *Server) sendToUser(user *User, msg Message) {
	data, err := json.Marshal(msg)
	if err != nil {
		log.Printf("Error marshaling message: %v", err)
		return
	}

	user.mu.Lock()
	defer user.mu.Unlock()

	err = user.Conn.WriteMessage(websocket.TextMessage, data)
	if err != nil {
		log.Printf("Error sending to user %s: %v", user.Username, err)
	}
}

